+    // ── GoldenResult formatting ───────────────────────────────────────
+
+    #[test]
+    fn result_format_pass() {
+        let r = GoldenResult {
+            scenario: "test".into(),
+            outcome: GoldenOutcome::Pass,
+            checksums: vec![],
+            expected_checksums: vec![],
+            mismatch_index: None,
